class Solution:
    def findBestValue(self, arr, target):
        hi = max(arr)
        best_val = 0
        best_diff = None
        for v in range(hi + 1):
            s = sum(min(x, v) for x in arr)
            diff = abs(s - target)
            if best_diff is None or diff < best_diff:
                best_diff = diff
                best_val = v
        return best_val

