class Solution:
    def findBestValue(self, arr, target):
        hi = max(arr)
        def total(v):
            s = 0
            for x in arr:
                s += x if x < v else v
            return s
        lo, high = 0, hi
        while lo < high:
            mid = (lo + high) // 2
            if total(mid) >= target:
                high = mid
            else:
                lo = mid + 1
        candidates = [lo]
        if lo - 1 >= 0:
            candidates.append(lo - 1)
        best_val = None
        best_diff = None
        for v in sorted(candidates):
            diff = abs(total(v) - target)
            if best_diff is None or diff < best_diff:
                best_diff = diff
                best_val = v
        return best_val

