var findBestValue = function(arr, target) {
    const hi = Math.max(...arr);
    const total = (v) => {
        let s = 0;
        for (const x of arr) s += x < v ? x : v;
        return s;
    };
    let lo = 0, high = hi;
    while (lo < high) {
        const mid = (lo + high) >> 1;
        if (total(mid) >= target) high = mid;
        else lo = mid + 1;
    }
    const candidates = [lo];
    if (lo - 1 >= 0) candidates.push(lo - 1);
    candidates.sort((a, b) => a - b);
    let bestVal = null, bestDiff = null;
    for (const v of candidates) {
        const diff = Math.abs(total(v) - target);
        if (bestDiff === null || diff < bestDiff) {
            bestDiff = diff;
            bestVal = v;
        }
    }
    return bestVal;
};
